import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const AdminSidebar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const menuItems = [
    {
      path: '/admin',
      label: 'Dashboard',
      icon: '📊'
    },
    {
      path: '/admin/vehicles',
      label: 'Manage Vehicles',
      icon: '🚗'
    },
    {
      path: '/admin/customers',
      label: 'Manage Customers',
      icon: '👥'
    },
    {
      path: '/admin/bookings',
      label: 'Manage Bookings',
      icon: '📅'
    },
    {
      path: '/admin/payments',
      label: 'Manage Payments',
      icon: '💳'
    },
    {
      path: '/admin/returns',
      label: 'Manage Returns',
      icon: '🔄'
    },
    {
      path: '/admin/reports',
      label: 'Manage Reports',
      icon: '📈'
    },
    {
      path: '/admin/settings',
      label: 'Settings',
      icon: '⚙️'
    }
  ];

  const isActive = (path) => {
    return location.pathname === path;
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <aside className="sidebar admin-sidebar" style={styles.sidebar}>
      <nav className="sidebar-nav" style={styles.sidebarNav}>
        <ul className="sidebar-menu" style={styles.sidebarMenu}>
          {menuItems.map((item) => (
            <li key={item.path} className="sidebar-item" style={styles.sidebarItem}>
              <Link 
                to={item.path} 
                className={`sidebar-link ${isActive(item.path) ? 'active' : ''}`}
                style={{
                  ...styles.sidebarLink,
                  ...(isActive(item.path) ? styles.sidebarLinkActive : {})
                }}
              >
                <span className="sidebar-icon" style={styles.sidebarIcon}>{item.icon}</span>
                <span className="sidebar-label" style={styles.sidebarLabel}>{item.label}</span>
              </Link>
            </li>
          ))}
        </ul>
      </nav>

      <div className="sidebar-footer" style={styles.sidebarFooter}>
        {/* Profile Picture and Logout */}
        <div style={styles.profileSection}>
          <div style={styles.profileAvatar}>
            {user?.name?.charAt(0).toUpperCase() || 'A'}
          </div>
          <span style={styles.profileUsername}>{user?.name || 'Admin'}</span>
        </div>
        
        <button 
          onClick={handleLogout} 
          style={styles.logoutBtn}
          className="logout-button"
        >
          Logout
        </button>

        <div className="sidebar-stats" style={styles.sidebarStats}>
          <div className="stat-item" style={styles.statItem}>
            <span className="stat-label" style={styles.statLabel}>Role</span>
            <span className="stat-value" style={styles.statValue}>
              Administrator
            </span>
          </div>
        </div>
      </div>

      <style>{`
        .admin-sidebar {
          background-color: #000F5B !important;
        }
        .sidebar-link:hover {
          background-color: rgba(255, 255, 255, 0.1) !important;
        }
        .logout-button:hover {
          background-color: #c0392b !important;
        }
      `}</style>
    </aside>
  );
};

const styles = {
  sidebar: {
    width: '250px',
    backgroundColor: '#000F5B',
    color: 'white',
    display: 'flex',
    flexDirection: 'column',
    height: '100vh',
    position: 'fixed',
    left: 0,
    top: '60px',
    zIndex: 999,
  },
  sidebarNav: {
    flex: 1,
    padding: '15px 0',
    overflowY: 'auto',
  },
  sidebarMenu: {
    listStyle: 'none',
    padding: 0,
    margin: 0,
  },
  sidebarItem: {
    marginBottom: '5px',
  },
  sidebarLink: {
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    padding: '12px 15px',
    color: 'rgba(255, 255, 255, 0.8)',
    textDecoration: 'none',
    borderRadius: '8px',
    margin: '0 10px',
    transition: 'all 0.3s ease',
    fontFamily: 'Inria Serif, serif',
  },
  sidebarLinkActive: {
    backgroundColor: '#3f42c7',
    color: 'white',
  },
  sidebarIcon: {
    fontSize: '18px',
  },
  sidebarLabel: {
    fontSize: '14px',
    fontWeight: '500',
    fontFamily: 'Inria Serif, serif',
  },
  sidebarFooter: {
    padding: '15px',
    borderTop: '1px solid rgba(255, 255, 255, 0.1)',
  },
  profileSection: {
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    marginBottom: '15px',
    padding: '10px',
    backgroundColor: 'rgba(255, 255, 255, 0.1)',
    borderRadius: '8px',
  },
  profileAvatar: {
    width: '40px',
    height: '40px',
    borderRadius: '50%',
    backgroundColor: '#3f42c7',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: 'white',
    fontSize: '18px',
    fontWeight: 'bold',
    fontFamily: 'Inria Serif, serif',
  },
  profileUsername: {
    fontSize: '14px',
    fontWeight: '600',
    color: 'white',
    fontFamily: 'Inria Serif, serif',
  },
  logoutBtn: {
    width: '100%',
    padding: '10px 15px',
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '14px',
    fontWeight: '600',
    cursor: 'pointer',
    marginBottom: '15px',
    transition: 'background-color 0.3s ease',
    fontFamily: 'Inria Serif, serif',
  },
  sidebarStats: {
    paddingTop: '10px',
  },
  statItem: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px',
  },
  statLabel: {
    fontSize: '12px',
    color: 'rgba(255, 255, 255, 0.6)',
    fontFamily: 'Inria Serif, serif',
  },
  statValue: {
    fontSize: '14px',
    fontWeight: '600',
    color: 'white',
    fontFamily: 'Inria Serif, serif',
  },
};

export default AdminSidebar;
